%%%%%%%%%% Function plotCalib.m %%%%%%%%%%% Kei Nakamura% Thursday, December 1st 2005.% Modified on% function plotdataNew = plotCalib(plotdata,scan)% returns the calibrated x axis for plotfunction plotdataNew = plotCalib(plotdata,scan) %function headerplotdataNew = plotdata;plotSiz = size(plotdata);if scan==6;    plotdataNew(:,1) = 5.0105*plotdata(:,1);    plotdataNew(:,1+plotsize(1,2)/2) = 5.0105*plotdata(:,1);elseif scan==7;    plotdataNew(:,1) = 1.7748*plotdata(:,1);    plotdataNew(:,1+plotsize(1,2)/2) = 1.7748*plotdata(:,1);%elseif scan==8;%    plotdataNew(:,1) = 1.487*plotdata(:,1);%    plotdataNew(:,1+plotsize(1,2)/2) = 1.487*plotdata(:,1);elseif scan==18;    plotdataNew(:,1) = plotdata(:,1)-43430;     %1012:42435,1014:42975,1017:43430,1019:43843,45664end
